//转换空格
x(/[ \t]+</g,'<');
x(/&nbsp;/g,' ');
//初始化分段准备
x(/[\t ]{2,2}/g,"　");
//初始化图片链接
x(/[\r\n]?[\t ]*<img .+?toimg\/data\/([^\.]+)[^>]+>[\t ]*[\r\n]?/g,"#$1#");

//初始化字体格式的文字,匹配<i>&#xe800</i>
x(/<i>([^<]*)<\/i>/g,function(str,p1){
