@js:
try {
	data = JSON.parse(source.getVariable())
} catch (err) {
	data = {}
}
url = data.url || baseUrl;
url + "s.php," + JSON.stringify({
	"charset": "GBK",
	"method": "POST",
	"body": "objectType=2&type=articlename&s=" + key + "&page=" + page
})

ruleContent.nextContentUrl:
.chapterPages@tag.a!0@href@js:
for (let i in result) {
	result[i] = String(result[i]).replace(/.+?\('\d+','\d+','(\d+)','(\d+)'\).+?/, (str, p1, p2) => p1 + '_' + p2 + '.html');
}
result

