sorts:["热门","新书","评分","字数"]
};
var categorySelection={
length:null,
status:null,
sort:null
};
function initCategorySelection(){
if(selectedItems.length>0){
for(var i=0;i<selectedItems.length;i++){
var item=selectedItems[i];
if(config.lengths.includes(item)){
categorySelection.length=item;
}else if(config.statuses.includes(item)){
categorySelection.status=item;
}else if(config.sorts.includes(item)){
categorySelection.sort=item;
}}}}
initCategorySelection();
function initButtons(containerId,items,category){
var container=document.getElementById(containerId);
var buttonsHTML='';
for(var i=0;i<items.length;i++){
var name=items[i];
var isSelected=categorySelection[category]===name;
buttonsHTML+='<button onclick="toggleSelection(\\''+name+'\\',\\''+category+'\\')" class="filter-btn'+(isSelected?' selected':'')+'">'+name+'</button>';
}
container.innerHTML=buttonsHTML;
}
function toggleSelection(name,category){
if(categorySelection[category]===name){
categorySelection[category]=null;
}else{
categorySelection[category]=name;
}
updateButtonStates();
updateOutput();
}
function updateButtonStates(){
for(var category in categorySelection){
var containerId=category+'-btns';
var container=document.getElementById(containerId);
if(container){
var buttons=container.getElementsByTagName('button');
for(var i=0;i<buttons.length;i++){
var btn=buttons[i];
var btnName=btn.textContent;
btn.className='filter-btn'+(categorySelection[category]===btnName?' selected':'');
}}}}
function updateOutput(){
var allSelected=[];
for(var category in categorySelection){
if(categorySelection[category]){
allSelected.push(categorySelection[category]);}}
var resultText=allSelected.length>0?allSelected.join(", "):"未选择";
document.getElementById('result-output').textContent=resultText;
}
function clearAll(){
categorySelection={length:null,status:null,sort:null};
updateButtonStates();
updateOutput();
}
initButtons('length-btns',config.lengths,'length');
initButtons('status-btns',config.statuses,'status');
initButtons('sort-btns',config.sorts,'sort');
updateOutput();
</script></body></html>`;

