let isAndroid = deviceType();
let title = chapter.title || "";

if (isAndroid) {
    let base64Str = baseUrl.replace('data:contentUrl;base64,', '').split(',')[0];
    let decoded = java.base64Decode(base64Str);

    let bookidMatch = decoded.match(/bookid=(\d+)/);
    let bookid = bookidMatch ? bookidMatch[1] : null;

    let chapteridMatch = decoded.match(/chapterid=(\d+)/);
    let chapterid = chapteridMatch ? chapteridMatch[1] : null;

    let yunparaStatus = java.get("yunpara") || "off";

    let isModifiedVersion = checkEnv();
    let isQingRead = isQRead();

    let isQQSource = /QQ阅读|企鹅看书/.test(decoded);

    if ((isModifiedVersion || isQingRead) && yunparaStatus == "on" && isQQSource && bookid && chapterid) {
        let Bubble = cache.get(bookid + "_" + chapterid) || "";
        title = title + Bubble;
    }
}
title;

