function parseContent(textData) {
    let result,message,emote;
    let pic="";
    var messageMatch = textData.match(/message=([^,]+?),/);
    if (messageMatch) {
        message = messageMatch[1].trim();      
    }
    let emoteMatch = textData.match(/text=\[.*?\],\s*url=[^,]+,/g);
    if(emoteMatch){
        emoteMatch.forEach(x=>{
            let title = x.match(/text=(\[.*?\])/)[1];   
            let url = x.match(/url=([^,]+),/)[1];  
            title = title.replace(/(\[|\]|\$)/g,'\\$1');   
            let re = new RegExp(title,"g");      

            let img = `<img src="${url},{style:'text'}">`;
            message = message.replace(re,img);         
        })
    }
    var picturesMatch = textData.match(/pictures=\[([^\]]+)\],/);
    if (picturesMatch) {
        var picturesBlock = picturesMatch[1];
        var srcMatch = picturesBlock.match(/"img_src":"([^"]+)"/g);        
        if(srcMatch){
            srcMatch.forEach(x=>{
                let src = x.match(/"img_src":"([^"]+)"/);        
                pic +=`<img src="${src[1].replace(/\\\//g, '/') }">`
            })
        }       
    }
    result = message+pic
    return result;
}



