function danmakuToLRC(xmlString, options = {}) {
  let {
    sortByTime = true,      
    timeFormat = 's',       
    includeMeta = true,     
    escapeChars = true 
  } = options;

  let danmakuPattern = new RegExp('<d\\s+p="([^"]+)">(.*?)</d>', 'g');
  let danmakus = [];
  let match;

  while ((match = danmakuPattern.exec(xmlString)) !== null) {
    let pAttribute = match[1];
    let textContent = match[2];
    let parts = pAttribute.split(',');

    if (parts.length >= 9) {
      let time = parseFloat(parts[0]);  
      let text = escapeChars 
        ? textContent.replace(/\[/g, '【').replace(/\]/g, '】')
        : textContent;

      danmakus.push({ time, text });
    }
  }

  if (sortByTime) {
    danmakus.sort((a, b) => a.time - b.time);
  }

  let lrcContent = '';

  if (includeMeta) {
    lrcContent += '[ti:弹幕歌词]\n';
    lrcContent += '[ar:Bilibili弹幕]\n';
    lrcContent += `[re:共${danmakus.length}条弹幕]\n`;
    lrcContent += `[by:danmaku-to-lrc ${new Date().toISOString().split('T')[0]}]\n\n`;
  }

  danmakus.forEach((danmaku, index) => {
    let timeTag = '';
    let minutes,seconds;
    if (timeFormat === 'ms') {
      let totalMs = danmaku.time * 1000;
      minutes = Math.floor(totalMs / 60000);
      seconds = Math.floor((totalMs % 60000) / 1000);
      let milliseconds = Math.floor(totalMs % 1000);
      timeTag = `[${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}.${milliseconds.toString().padStart(3, '0')}]`;
    } else {
      minutes = Math.floor(danmaku.time / 60);
      seconds = danmaku.time % 60;
      timeTag = `[${minutes.toString().padStart(2, '0')}:${seconds.toFixed(2).padStart(5, '0')}]`;
    }

    lrcContent += `${timeTag}${danmaku.text}\n`;
  });

  return lrcContent;
}

