        nodes[0].rich = node;
        html += getNodes(nodes);
    }) : null;

    if (module_dynamic.major) {
        html += getMajor(module_dynamic.major)
    }
    if (module_dynamic.additional) {
        html += getLinkCard(module_dynamic.additional)
    }

    let orig = item?.orig?.modules?.module_dynamic;
